using System;

class Program {
    static void Main() {
        byte  b = 255;
        short s = 32767;
        int   i = 2_147_483_647;
        long  l = 9_000_000_000L;
        Console.WriteLine($"{b} {s} {i} {l}");
    }
}

using System;

class Program {
    static void Main() {
        float  f = 3.14f;
        double d = 3.14159265;
        decimal m = 9.99m;
        Console.WriteLine($"{f} {d} {m}");
        Console.WriteLine($"{0.1m + 0.2m}");
    }
}

using System;

class Program {
    static void Main() {
        bool t = true;
        bool f = false;
        Console.WriteLine($"{t} {f}");
        Console.WriteLine(5 > 3);
        Console.WriteLine(5 == 5);
        Console.WriteLine(!true);
        Console.WriteLine(true && false);
        Console.WriteLine(true || false);
    }
}

using System;

class Program {
    static void Main() {
        char letter = 'A';
        char digit  = '9';
        char newline = '\n';
        Console.WriteLine(letter);
        Console.WriteLine(digit);
        Console.WriteLine((int)letter);
    }
}

using System;

class Program {
    static void Main() {
        double d = 9.99;
        int i = (int)d;  // truncates, not rounds
        Console.WriteLine($"{d} -> {i}");

        int x = 1000;
        byte b = (byte)x;  // wraps
        Console.WriteLine($"{x} -> {b}");
    }
}

using System;

class Program {
    static void Main() {
        int i = 100;
        long l = i;    // automatic: int -> long
        double d = i;  // automatic: int -> double
        Console.WriteLine($"{i} {l} {d}");
    }
}

using System;

class Program {
    static void Main() {
        string s = "42";
        int n = Convert.ToInt32(s);
        double d = Convert.ToDouble("3.14");
        string back = Convert.ToString(n);
        Console.WriteLine($"{n} {d} {back}");
    }
}

using System;

class Program {
    static void Main() {
        string input1 = "42";
        string input2 = "abc";

        if (int.TryParse(input1, out int n1)) {
            Console.WriteLine($"parsed: {n1}");
        }
        if (!int.TryParse(input2, out int n2)) {
            Console.WriteLine($"'{input2}' is not a number");
        }
    }
}
